using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;
using BenchmarkDotNet.Environments;
using BenchmarkDotNet.Jobs;
using BenchmarkDotNet.Running;
using TextAnalysis;

var config = DefaultConfig.Instance
    .AddJob(Job.Default.WithRuntime(CoreRuntime.Core90).WithId("net9.0"))
    .AddJob(Job.Default.WithRuntime(CoreRuntime.Core100).WithId("net10.0"));

BenchmarkRunner.Run<TextAnalyzerBenchmarks>(config);

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    // ~200 words of representative text
    private const string SampleText =
        "The quick brown fox jumps over the lazy dog. " +
        "A wizard's job is to vex chumps quickly in fog. " +
        "Pack my box with five dozen liquor jugs. " +
        "How vexingly quick daft zebras jump. " +
        "The five boxing wizards jump quickly. " +
        "Sphinx of black quartz judge my vow. " +
        "Two driven jocks help fax my big quiz. " +
        "The jay pig fox zebra and my wolves quack. " +
        "Sympathizing would fix Quaker objectives. " +
        "A very bad quack might jinx zippy fowls. " +
        "Few quips galvanized the mock jury box. " +
        "The quick brown fox jumps over the lazy dog again and again. " +
        "Performance testing is important for understanding runtime behavior. " +
        "Benchmarking helps developers identify bottlenecks in their code. " +
        "Careful measurement ensures accurate and reproducible results across runs. " +
        "Statistical analysis of benchmark data reveals meaningful performance differences. " +
        "Modern runtimes apply just in time compilation and garbage collection optimizations. " +
        "Memory allocation patterns significantly impact application throughput and latency.";

    [GlobalSetup]
    public void Setup()
    {
        _analyzer = new TextAnalyzer(SampleText);
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

